class SendChatActionMethod(BaseModel):
    """
    Use this method when you need to tell the user that something is
    happening on the bot's side. The status is set for 5 seconds or less
    (when a message arrives from your bot, Telegram clients clear its typing
    status). Returns True on success.

    Example: The ImageBot needs some time to process a request and upload
    the image. Instead of sending a text message along the lines of
    “Retrieving image, please wait…”, the bot may use sendChatAction with
    action = upload_photo. The user will see a “sending photo” status for
    the bot.

    We only recommend using this method when a response from the bot will
    take a noticeable amount of time to arrive.

    See https://core.telegram.org/bots/api#sendchataction
    """
  
    chat_id: ChatID
    """
    Unique identifier for the target chat or username of the target bot or
    supergroup in the format @username. Channel chats and channel direct
    messages chats aren't supported.
    """ 
    action: str
    """
    Type of action to broadcast. Choose one, depending on what the user is
    about to receive: typing for text messages, upload_photo for photos,
    record_video or upload_video for videos, record_voice or upload_voice
    for voice notes, upload_document for general files, choose_sticker for
    stickers, find_location for location data, record_video_note or
    upload_video_note for video notes.
    """ 
    business_connection_id: str | None = None
    """
    Unique identifier of the business connection on behalf of which the
    action will be sent
    """ 
    message_thread_id: int | None = None
    """
    Unique identifier for the target message thread or topic of a forum; for
    supergroups and private chats of bots with forum topic mode enabled only
    """

    async def call(self, conn: Connection) -> bool:
        payload = _MultipartPayload()
        self.chat_id._write(payload, "chat_id")
        _StrPart(self.action)._write(payload, "action")
        if self.business_connection_id is not None:
            _StrPart(self.business_connection_id)._write(payload, "business_connection_id")
        if self.message_thread_id is not None:
            _IntPart(self.message_thread_id)._write(payload, "message_thread_id")
        return await conn.do(Method.SendChatAction, payload, TypeAdapter(bool)) 

 
