class SendGiftMethod(BaseModel):
    """
    Sends a gift to the given user or channel chat. The gift can't be
    converted to Telegram Stars by the receiver. Returns True on success.

    See https://core.telegram.org/bots/api#sendgift
    """
  
    gift_id: str
    """Identifier of the gift; limited gifts can't be sent to channel chats""" 
    user_id: int | None = None
    """
    Required if chat_id is not specified. Unique identifier of the target
    user who will receive the gift.
    """ 
    chat_id: ChatID | None = None
    """
    Required if user_id is not specified. Unique identifier for the chat or
    username of the channel (in the format @username) that will receive the
    gift.
    """ 
    pay_for_upgrade: bool | None = None
    """
    Pass True to pay for the gift upgrade from the bot's balance, thereby
    making the upgrade free for the receiver
    """ 
    text: str | None = None
    """Text that will be shown along with the gift; 0-128 characters""" 
    text_parse_mode: str | None = None
    """
    Mode for parsing entities in the text. See formatting options for more
    details. Entities other than “bold”, “italic”, “underline”,
    “strikethrough”, “spoiler”, “custom_emoji”, and “date_time” are ignored.
    """ 
    text_entities: list[MessageEntity] | None = None
    """
    A JSON-serialized list of special entities that appear in the gift text.
    It can be specified instead of text_parse_mode. Entities other than
    “bold”, “italic”, “underline”, “strikethrough”, “spoiler”,
    “custom_emoji”, and “date_time” are ignored.
    """

    async def call(self, conn: Connection) -> bool:
        payload = _MultipartPayload()
        _StrPart(self.gift_id)._write(payload, "gift_id")
        if self.user_id is not None:
            _IntPart(self.user_id)._write(payload, "user_id")
        if self.chat_id is not None:
            self.chat_id._write(payload, "chat_id")
        if self.pay_for_upgrade is not None:
            _BoolPart(self.pay_for_upgrade)._write(payload, "pay_for_upgrade")
        if self.text is not None:
            _StrPart(self.text)._write(payload, "text")
        if self.text_parse_mode is not None:
            _StrPart(self.text_parse_mode)._write(payload, "text_parse_mode")
        if self.text_entities is not None:
            _ObjectListPart(self.text_entities)._write(payload, "text_entities")
        return await conn.do(Method.SendGift, payload, TypeAdapter(bool)) 

 
