class EditMessageLiveLocationMethod(BaseModel):
    """
    Use this method to edit live location messages. A location can be edited
    until its live_period expires or editing is explicitly disabled by a
    call to stopMessageLiveLocation. On success, if the edited message is
    not an inline message, the edited Message is returned, otherwise True is
    returned.

    See https://core.telegram.org/bots/api#editmessagelivelocation
    """
  
    latitude: float
    """Latitude of new location""" 
    longitude: float
    """Longitude of new location""" 
    business_connection_id: str | None = None
    """
    Unique identifier of the business connection on behalf of which the
    message to be edited was sent
    """ 
    chat_id: ChatID | None = None
    """
    Required if inline_message_id is not specified. Unique identifier for
    the target chat or username of the target bot, supergroup or channel in
    the format @username.
    """ 
    message_id: int | None = None
    """
    Required if inline_message_id is not specified. Identifier of the
    message to edit.
    """ 
    inline_message_id: str | None = None
    """
    Required if chat_id and message_id are not specified. Identifier of the
    inline message.
    """ 
    live_period: int | None = None
    """
    New period in seconds during which the location can be updated, starting
    from the message send date. If 0x7FFFFFFF is specified, then the
    location can be updated forever. Otherwise, the new value must not
    exceed the current live_period by more than a day, and the live location
    expiration date must remain within the next 90 days. If not specified,
    then live_period remains unchanged.
    """ 
    horizontal_accuracy: float | None = None
    """The radius of uncertainty for the location, measured in meters; 0-1500""" 
    heading: int | None = None
    """
    Direction in which the user is moving, in degrees. Must be between 1 and
    360 if specified.
    """ 
    proximity_alert_radius: int | None = None
    """
    The maximum distance for proximity alerts about approaching another chat
    member, in meters. Must be between 1 and 100000 if specified.
    """ 
    reply_markup: InlineKeyboardMarkup | None = None
    """A JSON-serialized object for a new inline keyboard"""

    async def call(self, conn: Connection) -> MaybeMessage:
        payload = _MultipartPayload()
        _FloatPart(self.latitude)._write(payload, "latitude")
        _FloatPart(self.longitude)._write(payload, "longitude")
        if self.business_connection_id is not None:
            _StrPart(self.business_connection_id)._write(payload, "business_connection_id")
        if self.chat_id is not None:
            self.chat_id._write(payload, "chat_id")
        if self.message_id is not None:
            _IntPart(self.message_id)._write(payload, "message_id")
        if self.inline_message_id is not None:
            _StrPart(self.inline_message_id)._write(payload, "inline_message_id")
        if self.live_period is not None:
            _IntPart(self.live_period)._write(payload, "live_period")
        if self.horizontal_accuracy is not None:
            _FloatPart(self.horizontal_accuracy)._write(payload, "horizontal_accuracy")
        if self.heading is not None:
            _IntPart(self.heading)._write(payload, "heading")
        if self.proximity_alert_radius is not None:
            _IntPart(self.proximity_alert_radius)._write(payload, "proximity_alert_radius")
        if self.reply_markup is not None:
            self.reply_markup._write(payload, "reply_markup")
        return await conn.do(Method.EditMessageLiveLocation, payload, TypeAdapter(MaybeMessage)) 

 
