class SendStickerMethod(BaseModel):
    """
    Use this method to send static .WEBP, animated .TGS, or video .WEBM
    stickers. On success, the sent Message is returned.

    See https://core.telegram.org/bots/api#sendsticker
    """
  
    chat_id: ChatID
    """
    Unique identifier for the target chat or username of the target bot,
    supergroup or channel in the format @username
    """ 
    sticker: InputFile
    """
    Sticker to send. Pass a file_id as String to send a file that exists on
    the Telegram servers (recommended), pass an HTTP URL as a String for
    Telegram to get a .WEBP sticker from the Internet, or upload a new
    .WEBP, .TGS, or .WEBM sticker using multipart/form-data. More
    information on Sending Files ». Video and animated stickers can't be
    sent via an HTTP URL.
    """ 
    business_connection_id: str | None = None
    """
    Unique identifier of the business connection on behalf of which the
    message will be sent
    """ 
    message_thread_id: int | None = None
    """
    Unique identifier for the target message thread (topic) of a forum; for
    forum supergroups and private chats of bots with forum topic mode
    enabled only
    """ 
    direct_messages_topic_id: int | None = None
    """
    Identifier of the direct messages topic to which the message will be
    sent; required if the message is sent to a direct messages chat
    """ 
    emoji: str | None = None
    """Emoji associated with the sticker; only for just uploaded stickers""" 
    disable_notification: bool | None = None
    """
    Sends the message silently. Users will receive a notification with no
    sound.
    """ 
    protect_content: bool | None = None
    """Protects the contents of the sent message from forwarding and saving""" 
    allow_paid_broadcast: bool | None = None
    """
    Pass True to allow up to 1000 messages per second, ignoring broadcasting
    limits for a fee of 0.1 Telegram Stars per message. The relevant Stars
    will be withdrawn from the bot's balance.
    """ 
    message_effect_id: str | None = None
    """
    Unique identifier of the message effect to be added to the message; for
    private chats only
    """ 
    suggested_post_parameters: SuggestedPostParameters | None = None
    """
    A JSON-serialized object containing the parameters of the suggested post
    to send; for direct messages chats only. If the message is sent as a
    reply to another suggested post, then that suggested post is
    automatically declined.
    """ 
    reply_parameters: ReplyParameters | None = None
    """Description of the message to reply to""" 
    reply_markup: ReplyMarkup | None = None
    """
    Additional interface options. A JSON-serialized object for an inline
    keyboard, custom reply keyboard, instructions to remove a reply keyboard
    or to force a reply from the user.
    """

    async def call(self, conn: Connection) -> Message:
        payload = _MultipartPayload()
        self.chat_id._write(payload, "chat_id")
        self.sticker._write(payload, "sticker")
        if self.business_connection_id is not None:
            _StrPart(self.business_connection_id)._write(payload, "business_connection_id")
        if self.message_thread_id is not None:
            _IntPart(self.message_thread_id)._write(payload, "message_thread_id")
        if self.direct_messages_topic_id is not None:
            _IntPart(self.direct_messages_topic_id)._write(payload, "direct_messages_topic_id")
        if self.emoji is not None:
            _StrPart(self.emoji)._write(payload, "emoji")
        if self.disable_notification is not None:
            _BoolPart(self.disable_notification)._write(payload, "disable_notification")
        if self.protect_content is not None:
            _BoolPart(self.protect_content)._write(payload, "protect_content")
        if self.allow_paid_broadcast is not None:
            _BoolPart(self.allow_paid_broadcast)._write(payload, "allow_paid_broadcast")
        if self.message_effect_id is not None:
            _StrPart(self.message_effect_id)._write(payload, "message_effect_id")
        if self.suggested_post_parameters is not None:
            self.suggested_post_parameters._write(payload, "suggested_post_parameters")
        if self.reply_parameters is not None:
            self.reply_parameters._write(payload, "reply_parameters")
        if self.reply_markup is not None:
            self.reply_markup._write(payload, "reply_markup")
        return await conn.do(Method.SendSticker, payload, TypeAdapter(Message)) 

 
