    async def call(self, conn: Connection) -> MaybeMessage:
        payload = _MultipartPayload()
        _IntPart(self.user_id)._write(payload, "user_id")
        _IntPart(self.score)._write(payload, "score")
        if self.force is not None:
            _BoolPart(self.force)._write(payload, "force")
        if self.disable_edit_message is not None:
            _BoolPart(self.disable_edit_message)._write(payload, "disable_edit_message")
        if self.chat_id is not None:
            _IntPart(self.chat_id)._write(payload, "chat_id")
        if self.message_id is not None:
            _IntPart(self.message_id)._write(payload, "message_id")
        if self.inline_message_id is not None:
            _StrPart(self.inline_message_id)._write(payload, "inline_message_id")
        return await conn.do(Method.SetGameScore, payload, TypeAdapter(MaybeMessage)) 

 
